import type { FC } from 'react';
import React from 'react';
import clsx from 'clsx';
import type { TabPaneProps } from './TabsContext';
import { UD_TABPANE_ID, useTabsContext } from './TabsContext';
import { useRenderStatus, RenderStatus } from '../hooks/useRenderStatus';
import { devWarning, warning } from '../util';

import './style';

export const TabPane: FC<TabPaneProps> = props => {
  const { style, className, children, internalKey, forceRender = false, destroyOnHide = false } = props;

  warning(
    !(forceRender && destroyOnHide),
    devWarning('TabPane', 'should not set `forceRender` and `destroyonHide` at same time.'),
  );

  const { activeKey, rootCssScope } = useTabsContext();
  const active = activeKey === internalKey;

  const renderStatus = useRenderStatus({ active, forceRender, destroyOnHide });

  if (renderStatus === RenderStatus.discard) {
    return null;
  }

  const cls = clsx(
    rootCssScope('__pane'),
    {
      [rootCssScope('__pane--inactive')]: renderStatus === RenderStatus.cache,
    },
    className,
  );

  return (
    <div style={style} className={cls} data-testid="ud__tab-pane">
      {children}
    </div>
  );
};
if (__DEV__) {
  TabPane.displayName = 'TabPane';
}
Object.assign(TabPane, {
  [UD_TABPANE_ID]: true,
});
